import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class SecureServlet extends HttpServlet {

    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");

        // Sanitize and encode user input to prevent XSS
        String safeUserInput = sanitizeUserInput(userInput);

        // Output sanitized user input to the response
        PrintWriter out = response.getWriter();
        out.println("<html>");
        out.println("<body>");
        out.println("User Input: " + safeUserInput); // Safe output
        out.println("</body>");
        out.println("</html>");
    }

    private String sanitizeUserInput(String userInput) {
        // Implement proper input validation and encoding here
        // Example: Using OWASP Java Encoder library for HTML encoding
        return org.owasp.encoder.Encode.forHtml(userInput);
    }
}

